mapper.select:
SELECT a.id AS withdrawWayId, a.withdraw_way_i18 AS withdrawWayName, a.withdraw_type_id AS withdrawType,
(SELECT withdraw_type_i18 FROM system_withdraw_type WHERE id = a.withdraw_type_id) AS withdrawTypeName, IFNULL(t1.way_fee, a.way_fee) AS withdrawFee, IFNULL(t1.fee_type, a.fee_type) AS feeType, IFNULL(t1.way_fee_fixed_amount, a.way_fee_fixed_amount) AS wayFeeFixedAmount,
a.way_icon AS wayIcon, a.memo AS memo, a.status AS status,
CASE WHEN t1.created_time IS NOT NULL THEN t1.created_time ELSE a.updated_time END AS operatorTime,
CASE WHEN t1.creator IS NOT NULL THEN t1.creator ELSE a.updater END AS operator,
CASE WHEN a.id = t1.withdraw_id THEN 1 ELSE 0 END AS chooseFlag
FROM ( SELECT t.id, t.withdraw_way, t.withdraw_way_i18, t.withdraw_type_id, t.way_fee_fixed_amount, t.fee_type, t.way_icon, t.way_fee, t.memo, t.status, t.sort_order, t.updated_time, t.updater, t.withdraw_type_code, COUNT(swc.id) AS channelTotal
FROM system_withdraw_way t JOIN system_withdraw_type t2 ON t.withdraw_type_id = t2.id LEFT JOIN system_withdraw_channel swc ON swc.withdraw_way_id = t.id WHERE t.currency_code = #{vo.currency}
AND t2.id = #{vo.withdrawTypeId}
AND t.id = #{vo.withdrawWayId}
AND t.status = #{vo.status}
GROUP BY t.id, t.withdraw_way, t.withdraw_way_i18, t.withdraw_type_id, t.way_icon, t.way_fee, t.memo, t.status, t.sort_order, t.updated_time, t.updater ) a
LEFT JOIN site_withdraw_way t1 ON a.id = t1.withdraw_id AND t1.site_code = #{vo.siteCode} WHERE ( a.channelTotal > 0 or a.withdraw_type_code = 'manual_withdraw') ORDER BY chooseFlag DESC, a.status DESC, a.sort_order DESC

SELECT a.id AS id, b.currency_code AS currencyCode, a.withdraw_id AS withdrawWayId, b.withdraw_way_i18 AS withdrawWayI18, b.withdraw_type_code AS withdrawTypeCode, b.way_icon AS wayIcon, a.fee_type AS feeType, a.way_fee AS wayFee, a.way_fee_fixed_amount AS wayFeeFixedAmount, a.status AS status, a.sort_order AS sortOrder, a.creator AS creator, a.created_time AS createdTime, a.updater AS updater, a.updated_time AS updatedTime, c.withdraw_type_i18 AS withdrawTypeI18 FROM site_withdraw_way a LEFT JOIN system_withdraw_way b ON b.id = a.withdraw_id LEFT JOIN system_withdraw_type c ON c.id = b.withdraw_type_id WHERE a.site_code = #{vo.siteCode}
AND c.id = #{vo.withdrawTypeId}
AND b.currency_code = #{vo.currencyCode}
AND b.withdraw_way LIKE CONCAT('%', #{vo.withdrawWay}, '%')
AND a.status = #{vo.status}
AND a.fee_type = #{vo.feeType}
ORDER BY a.updated_time DESC

SELECT a.id AS id, b.currency_code AS currencyCode, a.withdraw_id AS withdrawWayId, b.withdraw_way_i18 AS withdrawWayI18, b.withdraw_type_code AS withdrawTypeCode, b.way_icon AS wayIcon, a.fee_type AS feeType, a.way_fee AS wayFee, a.way_fee_fixed_amount AS wayFeeFixedAmount, a.status AS status, a.sort_order AS sortOrder, a.creator AS creator, a.created_time AS createdTime, a.updater AS updater, a.updated_time AS updatedTime, c.withdraw_type_i18 AS withdrawTypeI18 FROM site_withdraw_way a LEFT JOIN system_withdraw_way b ON b.id = a.withdraw_id LEFT JOIN system_withdraw_type c ON c.id = b.withdraw_type_id WHERE a.site_code = #{vo.siteCode}
AND c.id = #{vo.withdrawTypeId}
AND b.currency_code = #{vo.currencyCode}
AND b.withdraw_way LIKE CONCAT('%', #{vo.withdrawWay}, '%')
AND a.status = #{vo.status}
AND a.fee_type = #{vo.feeType}
ORDER BY a.sort_order ASC

SELECT b.id AS id, b.currency_code AS currencyCode, b.withdraw_type_id AS withdrawTypeId, b.withdraw_type_code AS withdrawTypeCode, b.withdraw_way AS withdrawWay, b.withdraw_way_i18 AS withdrawWayI18, b.network_type AS networkType, b.fee_type AS feeType, b.way_fee AS wayFee, b.way_fee_fixed_amount AS wayFeeFixedAmount, b.quick_amount AS quickAmount, b.way_icon AS wayIcon, b.memo AS memo, b.recommend_flag AS recommendFlag FROM site_withdraw_way a LEFT JOIN system_withdraw_way b ON b.id = a.withdraw_id LEFT JOIN system_withdraw_type c ON c.id = b.withdraw_type_id WHERE a.site_code = #{vo.siteCode} AND a.status = 1 AND b.status = 1
AND b.currency_code = #{vo.mainCurrency}
ORDER BY b.recommend_flag DESC, a.sort_order ASC
